css:
.page-break {
  page-break-before: always !important;
  break-before: page !important;
  display: block;
  height: 1px;
  margin: 0;
  padding: 0;
}

.staffel-table {
  width: 100%;
  border-collapse: collapse;
  margin: 8px 0 14px;
}

.staffel-table th,
.staffel-table td {
  border: 1px solid #ddd;
  padding: 4px 6px;
}

.staffel-table tr.is-current td {
  background: #fff3cd;
  font-weight: 700;
}
